export const parseRawServerSliderOptionValue = (value) => {
    if (typeof value !== 'string')
        return;
    const parsed = +value;
    if (Number.isNaN(parsed))
        return;
    return parsed;
};
export const normalizeServerSliderOptionValue = (value, option) => value !== undefined && value >= option.min && value <= option.max ? value : option.def;
export const serializeServerSliderOptionValue = (value) => `${value}`;
export const toServerSliderOption = (localize, query, option) => ({
    query,
    name: localize(option.name),
    description: option.description && localize(option.description),
    required: option.required,
    type: option.type,
    def: option.def,
    min: option.min,
    max: option.max,
    step: option.step,
    unit: option.unit && localize(option.unit),
});
